<template>
  <div class="box">
    <div class="bread">
      <el-breadcrumb separator-class="el-icon-arrow-right">
        <el-breadcrumb-item :to="{ path: '/store/qg' }"
          >首页</el-breadcrumb-item
        >
        <el-breadcrumb-item>用户管理</el-breadcrumb-item>
        <el-breadcrumb-item>用户列表</el-breadcrumb-item>
      </el-breadcrumb>
    </div>
    <div class="table">
      <!-- 搜索部分 -->
      <div class="table-top">
        <div class="search">
          <el-input v-model="input" placeholder="请输入内容"></el-input>
          <p><i class="el-icon-search"></i></p>
        </div>
        <el-button type="primary" @click="dialogFormVisible = true">添加用户</el-button>
      </div>
      <!-- 表格部分 -->
      <el-table :data="user" border stripe width="100%">
        <!-- 下标 -->
        <el-table-column type="index" label="#"> </el-table-column>
        <el-table-column prop="username" label="姓名" width="180">
        </el-table-column>
        <el-table-column prop="email" label="邮箱"> </el-table-column>
        <el-table-column prop="mobile" label="电话" width="180">
        </el-table-column>
        <el-table-column prop="role_name" label="角色" width="180">
        </el-table-column>
        <!-- 状态 -->
        <el-table-column prop="mg_state" label="状态" width="180">
          <template slot-scope="scope">
            <!-- 开关 -->
            <el-switch
              v-model="scope.row.mg_state"
              active-color="#409EFF"
              inactive-color="#DCDFE6"
            >
            </el-switch>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="180">
              <!-- 3个按钮里面的，想要获取参数就要加这个telplate属性 -->
          <template slot-scope="scope">
            <!-- 修改 -->
           <el-button type="primary" icon="el-icon-edit"></el-button>
           <!-- 删除 -->
           <el-button
             type="danger"
             icon="el-icon-delete"
             @click="delUser(scope.row.id)"
           ></el-button>
           <!-- 修改角色 -->
           <el-button type="warning" icon="el-icon-setting"></el-button>
           </template>

        </el-table-column>
      </el-table>
      <!-- 分页器部分 -->
      <div class="block">
        <el-pagination
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
          :current-page="currentPage4"
          :page-sizes="[6, 200, 300, 2]"
          :page-size="2"
          layout="total, sizes, prev, pager, next, jumper"
          :total="Number(total)"
        >
        </el-pagination>
      </div>
    </div>


    <!-- 添加的弹框 -->
    <el-dialog title="添加用户" :visible.sync="dialogFormVisible">
      <!-- 输入框部分 -->
      <el-form
        :model="ruleForm"
        :rules="rules"
        ref="ruleForm"
        label-width="100px"
        class="demo-ruleForm"
      >
        <el-form-item label="用户名" prop="username">
          <el-input v-model="ruleForm.username"></el-input>
        </el-form-item>
        <el-form-item label="密码" prop="password">
          <el-input v-model="ruleForm.password"></el-input>
        </el-form-item>
        <el-form-item label="邮箱" prop="email">
          <el-input v-model="ruleForm.email"></el-input>
        </el-form-item>
        <el-form-item label="电话" prop="phone">
          <el-input v-model="ruleForm.phone"></el-input>
        </el-form-item>
      </el-form>
      <!-- 按钮部分 -->
      <div slot="footer" class="dialog-footer">
        <el-button @click="dialogFormVisible = false">取 消</el-button>
        <el-button type="primary" @click="addUser">确 定</el-button>
      </div>
    </el-dialog>
  </div>
</template>


<script>
export default {
  // 组件名称
  name: "demo",
  // 组件参数 接收来自父组件的数据
  props: {},
  // 局部注册的组件
  components: {},
  // 组件状态值
  data() {
    return {
      user: [], //获取的数据
      input: "", //输入框
      currentPage4: 1, //分页所需
      value: true,
      //   添加弹框里的数据
      dialogFormVisible: false,
      formLabelWidth: "100px",
      total:'',
      // 添加提示输入框
      ruleForm: {
        username: "",
        password:"",
        email:"",
        phone:"",
      },
      // 规则
      rules: {
        username: [
          { required: true, message: "请输入用户名", trigger: "blur" },
          // { min: 3, max: 5, message: '长度在 3 到 5 个字符', trigger: 'blur' }
        ],
        password: [
          { required: true, message: "请输入密码", trigger: "blur" },
          // { min: 3, max: 5, message: '长度在 3 到 5 个字符', trigger: 'blur' }
        ],
        email: [
          { required: true, message: "请输入邮箱地址", trigger: "blur" },
          //   { type: 'email', message: '请输入正确的邮箱地址', trigger: ['blur', 'change'] }
        ],
        phone: [{ required: true, message: "请输入电话", trigger: "blur" }],
      },
    };
  },
  // 计算属性
  computed: {},
  // 侦听器
  watch: {},
  // 组件方法
  methods: {
    //   获取接口数据
    async getMsg(a,c) {
      let { data: msg } = await this.$http.get('/users?pagenum='+a+'&pagesize='+c+'');
      this.user = msg.data.users;
      console.log(msg);
      this.total=msg.data.total
      console.log(this.total)
    //   console.log(this.user);
    },
    handleSizeChange(val,b=1) {
      console.log(`每页 ${val} 条`);
      this.getMsg(b,val)


    },
    handleCurrentChange(val,b=2) {
      console.log(`当前页: ${val}`);
      this.getMsg(val,b)
    },
    //   添加用户
    async addUser() {
      let add = await this.$http.post('users',{
        "username":this.ruleForm.username,
        "password":this.ruleForm.password,
        "email":this.ruleForm.email,
        "mobile":this.ruleForm.phone,
      })
      console.log(add);
      this.dialogFormVisible = false;
    },
    //   删除
    delUser(a) {
      // console.log(a);
      this.$confirm("此操作将永久删除该文件, 是否继续?", "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning",
      })
        .then(() => {
          this.$message({
            type: "success",
            message: "删除成功!",
          });
          this.$http.delete('/users/'+a).then(res=>{
                console.log(res)
            })
        })
        .catch(() => {
          this.$message({
            type: "info",
            message: "已取消删除",
          });
        });
    },
  },
  mounted() {
    this.getMsg(1,2);
  },
};
</script>


